phase1.code:
// ---- Basic class with primary constructor ----
class User(val name: String, var age: Int)

// ---- Class with properties and methods ----
class Person(
    val firstName: String,
    val lastName: String,
    var age: Int = 0
) {
    // Property with custom getter
    val fullName: String
        get() = "$firstName $lastName"

    // Method
    fun introduce() {
        println("Hi, I'm $fullName and I'm $age years old.")
    }

    // Method with return
    fun canVote(): Boolean = age >= 18
}

// ---- Class with init block ----
class Customer(val name: String, val email: String) {
    init {
        require(name.isNotBlank()) { "Name cannot be blank" }
        require(email.contains("@")) { "Invalid email" }
        println("Customer created: $name ($email)")
    }
}

// ---- Secondary constructor ----
class Product {
    val name: String
    val price: Double

    // Primary constructor is implicit
    constructor(name: String, price: Double) {
        this.name = name
        this.price = price
    }

    constructor(name: String) : this(name, 0.0) {
        println("Product with default price: $name")
    }

    fun display() = println("Product: $name, Price: $price")
}

// ---- Class with default values in primary constructor ----
class Car(
    val brand: String,
    val model: String = "Unknown",
    val year: Int = 2024
) {
    fun info() = println("$brand $model ($year)")
}

fun main() {
    // ---- Using classes ----
    val user = User("Alice", 25)
    println("User: ${user.name}, ${user.age}")
    user.age = 26
    println("Updated age: ${user.age}")

    // ---- Person class ----
    val person = Person("John", "Doe", 20)
    person.introduce()
    println("Can vote? ${person.canVote()}")

    // ---- Default parameters ----
    val person2 = Person("Jane", "Smith")
    person2.introduce()

    // ---- Init block ----
    val customer = Customer("Bob", "bob@example.com")
    // val invalid = Customer("", "noemail")  // Would throw exception

    // ---- Secondary constructors ----
    val product1 = Product("Laptop", 999.99)
    product1.display()
    val product2 = Product("Phone")
    product2.display()

    // ---- Default values ----
    val car1 = Car("Toyota")
    car1.info()
    val car2 = Car("Honda", "Civic", 2023)
    car2.info()
}

