phase3.solution:
class Book(
    val title: String,
    val author: String,
    var pages: Int = 0
) {
    init {
        println("Book created: $title")
    }

    fun displayInfo() {
        println("Title: $title, Author: $author, Pages: $pages")
    }
}

fun main() {
    val book1 = Book("Kotlin Basics", "Alice")
    book1.displayInfo()

    val book2 = Book("Advanced Kotlin", "Bob", 300)
    book2.displayInfo()
}
